      rounds.push({ round: r, offers: { ...currentOffers }, gap });
      const avgOffer = values.reduce((s, v) => s + v, 0) / values.length;
      const allAccept = positions.every((p) => avgOffer >= p.minAccept && avgOffer <= p.maxOffer);
