// src/stdlib-ai-native.ts
function createAiNativeModule() {
  return {
    // ── AI 모델 직접 호출 ────────────────────────────────────────────
    "ai-call": async (model, prompt) => {
      const anthropicKey = process.env.ANTHROPIC_API_KEY;
      const openaiKey = process.env.OPENAI_API_KEY;
      const apiKey = anthropicKey || openaiKey;
      const promptStr = typeof prompt === "string" ? prompt : typeof prompt === "object" && prompt !== null ? String(prompt.prompt || JSON.stringify(prompt)) : String(prompt);
      if (!apiKey) {
        return `[AI Mock Response] Model: ${model}, Prompt: ${promptStr.slice(0, 50)}...`;
      }
      if (anthropicKey && (model.startsWith("claude") || model.startsWith("anthropic"))) {
        try {
          const contextStr = typeof prompt === "object" && prompt !== null && prompt.context ? `

Context:
${JSON.stringify(prompt.context)}` : "";
          const maxTokens = typeof prompt === "object" && prompt !== null ? Number(prompt["max-tokens"] || prompt.maxTokens || 1024) : 1024;
          const res = await fetch("https://api.anthropic.com/v1/messages", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "x-api-key": anthropicKey,
              "anthropic-version": "2023-06-01"
            },
            body: JSON.stringify({
              model: model === "claude-3" ? "claude-3-haiku-20240307" : model,
              max_tokens: maxTokens,
              messages: [
                { role: "user", content: promptStr + contextStr }
              ]
            })
          });
          if (res.ok) {
            const data = await res.json();
            return data?.content?.[0]?.text ?? "[AI: empty response]";
          }
        } catch (e) {
          return `[AI Error] ${String(e)}`;
        }
      }
      if (openaiKey && (model.startsWith("gpt") || model.startsWith("openai"))) {
        try {
          const res = await fetch("https://api.openai.com/v1/chat/completions", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${openaiKey}`
            },
            body: JSON.stringify({
              model: model === "gpt-4" ? "gpt-4-turbo-preview" : model,
              messages: [{ role: "user", content: promptStr }]
            })
          });
          if (res.ok) {
            const data = await res.json();
            return data?.choices?.[0]?.message?.content ?? "[AI: empty response]";
          }
        } catch (e) {
          return `[AI Error] ${String(e)}`;
        }
      }
      return `[AI Mock Response] Model: ${model}, Prompt: ${promptStr.slice(0, 50)}...`;
    },
    // ── RAG 검색 ────────────────────────────────────────────────────
    "rag-search": (query, opts) => {
      const kb = opts?.kb ?? opts?.["kb"] ?? "default";
      const limit = Number(opts?.limit ?? opts?.["limit"] ?? 5);
      const mockResults = [
        { content: `Mock RAG result for: ${query}`, score: 0.95, source: String(kb) },
        { content: `Related: ${query} \u2014 context from ${kb}`, score: 0.82, source: String(kb) },
        { content: `Additional info about ${query}`, score: 0.74, source: String(kb) },
        { content: `Background: ${query} overview`, score: 0.61, source: String(kb) },
        { content: `Reference: ${query} documentation`, score: 0.53, source: String(kb) }
      ];
      return mockResults.slice(0, limit);
    },
    // ── 임베딩 생성 ─────────────────────────────────────────────────
    "embed": async (text) => {
      const gptPort = process.env.FREELANG_GPT_PORT ?? "30113";
      try {
        const res = await fetch(`http://localhost:${gptPort}/api/embed`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ text }),
          signal: AbortSignal.timeout ? AbortSignal.timeout(3e3) : void 0
        });
        if (res.ok) {
          const data = await res.json();
          if (Array.isArray(data?.embedding)) return data.embedding;
        }
      } catch {
      }
      return Array.from(
        { length: 10 },
        (_, i) => Math.sin((text.charCodeAt(i % text.length) + i * 7) * 0.1)
      );
    },
    // ── 코사인 유사도 ────────────────────────────────────────────────
    "similarity": (v1, v2) => {
      if (!Array.isArray(v1) || !Array.isArray(v2)) return 0;
      const len = Math.min(v1.length, v2.length);
      if (len === 0) return 0;
      let dot = 0, n1 = 0, n2 = 0;
      for (let i = 0; i < len; i++) {
        dot += v1[i] * v2[i];
        n1 += v1[i] ** 2;
        n2 += v2[i] ** 2;
      }
      const denom = Math.sqrt(n1) * Math.sqrt(n2);
      if (denom === 0) return 0;
      return dot / denom;
    },
    // ── 텍스트 청킹 (RAG 준비용) ─────────────────────────────────────
    "chunk-text": (text, size = 512, overlap = 50) => {
      if (typeof text !== "string" || text.length === 0) return [];
      const step = Math.max(1, size - overlap);
      const chunks = [];
      for (let i = 0; i < text.length; i += step) {
        chunks.push(text.slice(i, i + size));
        if (i + size >= text.length) break;
      }
      return chunks;
    },
    // ── 프롬프트 템플릿 변수 치환 ────────────────────────────────────
    "prompt-template": (template, vars) => {
      if (typeof template !== "string") return String(template);
      return template.replace(/\{(\w+)\}/g, (_, k) => String(vars?.[k] ?? ""));
    }
  };
}

// src/stdlib-test.ts
function createTestModule(callFn) {
  const results = [];
  let currentSuite = "";
  return {
    // describe: 테스트 그룹 이름 설정
    "describe": (name, fn) => {
      currentSuite = name;
      console.log(`
[${name}]`);
      if (fn !== void 0 && fn !== null) {
        try {
          callFn(fn, []);
        } catch (e) {
          console.error(`  describe '${name}' \uC624\uB958: ${e.message}`);
        }
      }
      return name;
    },
    // deftest: 개별 테스트 케이스 실행
    "deftest": (name, fn) => {
      const fullName = currentSuite ? `${currentSuite}/${name}` : name;
      try {
        callFn(fn, []);
        results.push({ name: fullName, passed: true });
        console.log(`  PASS  ${name}`);
        return true;
      } catch (e) {
        const err4 = e.message ?? String(e);
        results.push({ name: fullName, passed: false, error: err4 });
        console.log(`  FAIL  ${name}: ${err4}`);
        return false;
      }
    },
    // assert: 참인지 검증
    "assert": (val, msg) => {
      if (!val) {
        throw new Error(msg ?? `Assertion failed: ${JSON.stringify(val)}`);
      }
      return true;
    },
    // assert-eq: 두 값이 같은지 검증 (deep equal)
    "assert-eq": (a, b, msg) => {
      const aStr = JSON.stringify(a);
      const bStr = JSON.stringify(b);
      if (aStr !== bStr) {
        throw new Error(
          msg ?? `Expected ${bStr}, got ${aStr}`
        );
      }
      return true;
    },
    // assert-neq: 두 값이 다른지 검증
    "assert-neq": (a, b, msg) => {
      if (JSON.stringify(a) === JSON.stringify(b)) {
        throw new Error(
          msg ?? `Expected values to differ, but both are ${JSON.stringify(a)}`
        );
      }
      return true;
    },
    // assert-throws: fn 실행 시 예외가 발생해야 함
    "assert-throws": (fn, expectedMsg) => {
      try {
        callFn(fn, []);
        throw new Error(
          expectedMsg ? `Expected exception '${expectedMsg}' but none thrown` : "Expected exception but none thrown"
        );
      } catch (e) {
        if (e.message?.startsWith("Expected exception")) throw e;
        if (expectedMsg && !e.message?.includes(expectedMsg)) {
          throw new Error(
            `Expected exception containing '${expectedMsg}', got: ${e.message}`
          );
        }
        return true;
      }
    },
    // assert-nil: 값이 null/undefined인지
    "assert-nil": (val, msg) => {
      if (val !== null && val !== void 0) {
        throw new Error(msg ?? `Expected nil, got ${JSON.stringify(val)}`);
      }
      return true;
    },
    // assert-not-nil: 값이 null/undefined가 아닌지
    "assert-not-nil": (val, msg) => {
      if (val === null || val === void 0) {
        throw new Error(msg ?? `Expected non-nil, got nil`);
      }
      return true;
    },
    // test-report: 전체 결과 통계 출력 + 반환
    "test-report": () => {
      const passed = results.filter((r) => r.passed).length;
      const failed = results.length - passed;
      console.log(
        `
\uACB0\uACFC: ${passed}/${results.length} \uD1B5\uACFC${failed > 0 ? ` (${failed}\uAC1C \uC2E4\uD328)` : ""}`
      );
      if (failed > 0) {
        console.log("\uC2E4\uD328 \uBAA9\uB85D:");
        results.filter((r) => !r.passed).forEach((r) => console.log(`  - ${r.name}: ${r.error}`));
      }
      return { passed, failed, total: results.length, results };
    },
    // test-reset: 결과 초기화 (테스트 간 격리)
    "test-reset": () => {
      results.length = 0;
      currentSuite = "";
      return true;
    },
    // test-results: 현재 결과 배열 반환 (프로그래매틱 접근용)
    "test-results": () => results
  };
}

